"""Sync `Cursor` namespace + sub-namespaces."""

from __future__ import annotations

from ._client import _default_client
from .types import SDKModel, SDKRepository, SDKUser

# Re-imported for the type annotation only; pulling it through
# `_default_client` would create a cycle since `_client` imports
# nothing from `_cursor`.
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from ._client import Client


class _CursorModels:
    def list(
        self, *, client: "Client | None" = None, api_key: str | None = None
    ) -> list[SDKModel]:
        return (client or _default_client()).list_models(api_key=api_key)


class _CursorRepositories:
    def list(
        self, *, client: "Client | None" = None, api_key: str | None = None
    ) -> list[SDKRepository]:
        return (client or _default_client()).list_repositories(api_key=api_key)


class Cursor:
    models: _CursorModels = _CursorModels()
    repositories: _CursorRepositories = _CursorRepositories()

    @classmethod
    def me(
        cls, *, client: "Client | None" = None, api_key: str | None = None
    ) -> SDKUser:
        return (client or _default_client()).me(api_key=api_key)
